example:
-- Durante CREATE TABLE
CREATE TABLE empleados (
  id INT PRIMARY KEY,
  nombre VARCHAR(100)
);

-- Después de creada
ALTER TABLE empleados ADD CONSTRAINT PK_empleados_id PRIMARY KEY (id);

CREATE TABLE usuarios (
  id INT PRIMARY KEY,
  email VARCHAR(200) UNIQUE
);

-- O agregado después
ALTER TABLE usuarios ADD CONSTRAINT UQ_usuarios_email UNIQUE (email);

CREATE TABLE productos (
  id INT PRIMARY KEY,
  precio DECIMAL(10,2) CHECK (precio > 0)
);

ALTER TABLE empleados ADD CONSTRAINT CK_empleados_edad CHECK (edad >= 18 AND edad <= 120);

-- Inline en CREATE TABLE
CREATE TABLE pedidos (
  id INT PRIMARY KEY,
  cliente_id INT,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE CASCADE
);

-- Con CONSTRAINT explícito
CREATE TABLE pedidos (
  id INT PRIMARY KEY,
  cliente_id INT,
  CONSTRAINT FK_pedidos_clientes FOREIGN KEY (cliente_id) REFERENCES clientes(id)
);

-- Agregar después de la tabla
ALTER TABLE pedidos
ADD CONSTRAINT FK_pedidos_clientes
FOREIGN KEY (cliente_id) REFERENCES clientes(id);

-- Agregar una columna de fecha con valor por defecto (fecha actual)
ALTER TABLE empleados ADD fecha_ingreso DATE NOT NULL DEFAULT GETDATE();

-- Agregar una columna datetime con null permitido
ALTER TABLE pedidos ADD fecha_entrega DATETIME NULL;

-- Agregar columna de solo fecha (date) sin hora
ALTER TABLE facturas ADD fecha_emision DATE NOT NULL;

CREATE TABLE empleados (
  id INT IDENTITY(1,1) PRIMARY KEY,
  nombre VARCHAR(100) NOT NULL,
  fecha_nacimiento DATE,
  fecha_contratacion DATETIME DEFAULT GETDATE()
);

-- Cambiar una columna de DATE a DATETIME
ALTER TABLE empleados ALTER COLUMN fecha_contratacion DATETIME NOT NULL;

-- Cambiar una columna de VARCHAR(50) a VARCHAR(100)
ALTER TABLE clientes ALTER COLUMN direccion VARCHAR(100) NULL;

-- Insertar con fecha actual
INSERT INTO logs (mensaje, fecha) VALUES ('Inicio de sesión', GETDATE());

-- Usar en SELECT
SELECT GETDATE() AS ahora;
